cy.visit('/home');
cy.wait(3000);
const results = [];
// Extract all elements with their key attributes
cy.get('*').then($all => {
  $all.each((i, el) => {
    const $el = Cypress.$(el);
    const tag = el.tagName.toLowerCase();
    const cls = $el.attr('class') || '';
    const id = $el.attr('id') || '';
    const testid = $el.attr('data-testid') || '';
    const name = $el.attr('name') || '';
    const type = $el.attr('type') || '';
    const placeholder = $el.attr('placeholder') || '';
    const href = $el.attr('href') || '';
    const text = ($el.text() || '').trim().substring(0, 60);
    // Only capture meaningful elements
    if (['a', 'button', 'input', 'select', 'textarea'].includes(tag) || testid || cls && (cls.includes('nav') || cls.includes('cart') || cls.includes('product') || cls.includes('card') || cls.includes('header') || cls.includes('search') || cls.includes('category') || cls.includes('lang') || cls.includes('auth') || cls.includes('btn') || cls.includes('item') || cls.includes('menu'))) {
      results.push({
        tag,
        cls: cls.substring(0, 100),
        id,
        testid,
        name,
        type,
        placeholder,
        href,
        text
      });
    }
  });
}).then(() => {
  cy.writeFile('cypress/fixtures/dom-results.json', results);
});

