  cy.get('body').then($body => {
    const loginLink = $body.find('a').filter((i, el) => {
      const text = Cypress.$(el).text().toLowerCase();
      return text.includes('log') || text.includes('sign') || text.includes('login');
    });
    const hrefs = loginLink.map((i, el) => ({
      text: Cypress.$(el).text().trim(),
      href: Cypress.$(el).attr('href')
    })).get();
    cy.writeFile('cypress/fixtures/auth-links.json', hrefs);
  });
});
